import{_ as d,o as e,c as a,ag as r}from"./chunks/framework.Cqf6AMW8.js";const n=JSON.parse('{"title":"STM32 BKP备份寄存器","description":"STM32 BKP（备份寄存器）的配置和使用。","frontmatter":{"title":"STM32 BKP备份寄存器","description":"STM32 BKP（备份寄存器）的配置和使用。","date":"2026-04-21T00:00:00.000Z","tags":["STM32","BKP","备份寄存器","断电保护"],"sidebar":"auto"},"headers":[],"relativePath":"docs/hardware/stm32/stm32-18-BKP.md","filePath":"docs/hardware/stm32/stm32-18-BKP.md","lastUpdated":1776715536000}'),o={name:"docs/hardware/stm32/stm32-18-BKP.md"};function s(c,t,P,B,i,_){return e(),a("div",null,[...t[0]||(t[0]=[r('<h3 id="bkp-备份寄存器" tabindex="-1">BKP（备份寄存器） <a class="header-anchor" href="#bkp-备份寄存器" aria-label="Permalink to &quot;BKP（备份寄存器）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td>主要功能</td><td>存储用户应用程序数据</td></tr><tr><td>供电方式</td><td>VDD（2.0-3.6V）正常供电，VDD断电时由VBAT（1.8-3.6V）维持</td></tr><tr><td>数据保持</td><td>断电后依靠内置电源供电的RAM</td></tr><tr><td>数据清除</td><td>TAMPER引脚的侵入事件会清除所有备份寄存器内容</td></tr><tr><td>RTC相关功能</td><td>存储RTC时钟校准寄存器，RTC引脚输出RTC的准时钟、闹钟脉冲或秒脉冲</td></tr><tr><td>用户数据存储容量</td><td>20字节（中容量和小容量）<br>84字节（大容量和互联型）</td></tr></tbody></table><h3 id="bkp使用方法" tabindex="-1">BKP使用方法 <a class="header-anchor" href="#bkp使用方法" aria-label="Permalink to &quot;BKP使用方法&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>函数</th><th>说明</th></tr></thead><tbody><tr><td>开启BKP时钟</td><td><code>RCC_APB1PeriphClockCmd(RCC_APB1Periph_BKP, ENABLE)</code></td><td>使能BKP模块时钟</td></tr><tr><td>写入备份寄存器</td><td><code>BKP_WriteBackupRegister(BKP_DR1, 0xA5A5)</code></td><td>写入标志值，用于判断是否首次配置</td></tr><tr><td>读取备份寄存器</td><td><code>BKP_ReadBackupRegister(BKP_DR1)</code></td><td>读取标志值，判断是否需要重新配置</td></tr><tr><td>存储用户数据</td><td><code>BKP_WriteBackupRegister(BKP_DR2, data)</code></td><td>存储用户配置、系统状态等</td></tr><tr><td>读取用户数据</td><td><code>BKP_ReadBackupRegister(BKP_DR2)</code></td><td>恢复用户配置、系统状态等</td></tr></tbody></table>',4)])])}const l=d(o,[["render",s]]);export{n as __pageData,l as default};
